/**
 * Regenerates entrypoints/sdk/coreTypes.generated.ts from lazy Zod schemas
 * (dev/snapshot trees that omit the committed generated file).
 */
import { readFileSync, writeFileSync } from 'fs'
import { join } from 'path'

const root = join(import.meta.dirname, '..')
const coreSchemasPath = join(root, 'entrypoints', 'sdk', 'coreSchemas.ts')
const outPath = join(root, 'entrypoints', 'sdk', 'coreTypes.generated.ts')

const src = readFileSync(coreSchemasPath, 'utf8')
const names = []
const re = /^export const (\w+Schema) = lazySchema/gm
let m
while ((m = re.exec(src))) names.push(m[1])

const lines = [
  '/** Auto-generated by scripts/emit-core-types.mjs — do not edit by hand. */',
  "import type { z } from 'zod/v4'",
  `import {\n  ${names.join(',\n  ')},\n} from './coreSchemas.js'`,
  '',
]

for (const schema of names) {
  const typeName = schema.replace(/Schema$/, '')
  lines.push(
    `export type ${typeName} = z.infer<ReturnType<typeof ${schema}>>`,
  )
}

lines.push('')
writeFileSync(outPath, lines.join('\n'), 'utf8')
console.error(`Wrote ${names.length} types to ${outPath}`)
